const res = await fetch('https://<controller>/proxy/network/integration/v1/info', {
  headers: { 'X-API-Key': <API_KEY> }
});
const info = await res.json();

// npm i node-fetch fetch-cookie tough-cookie
import nodeFetch from 'node-fetch';
import tough from 'tough-cookie';
import fetchCookie from 'fetch-cookie';
const jar = new tough.CookieJar();
const fetch = fetchCookie(nodeFetch, jar);

const base = 'https://<controller>/proxy/network';
const res = await fetch(`${base}/api/login`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ username: <USERNAME>, password: <PASSWORD> })
});
if (!res.ok) throw new Error(`Login failed: ${res.status}`);
// Subsequent calls automatically send the TOKEN cookie from the jar
const me = await fetch(`${base}/v2/api/info`);
console.log('info', await me.json());

const res = await fetch('https://<controller>/proxy/network/integration/v1/sites?offset=0&limit=25', {
  headers: { 'X-API-Key': <API_KEY> }
});
const page = await res.json();

const siteId = <SITE_ID>;
const url = `https://<controller>/proxy/network/integration/v1/sites/${siteId}/devices?offset=0&limit=25`;
const res = await fetch(url, { headers: { 'X-API-Key': <API_KEY> }});
if (!res.ok) throw new Error(`HTTP ${res.status}`);
const page = await res.json();

